/* Kin QR — Compact byte-mode QR Code generator (types 1..6).
 * Algorithm derived from ISO/IEC 18004 + kazuhikoarase/qrcode-generator (MIT).
 * No version-info needed for type ≤ 6; supports up to ~134 bytes (EC L), enough for cleaned URLs.
 * Exposes window.KinQR = { encode, renderSVG }.
 */
(function (root) {
  'use strict';

  var MODE_BYTE = 4;
  var EC_BITS = { L: 1, M: 0, Q: 3, H: 2 };

  // [type][ecKey] -> array of [blockCount, totalCodewords, dataCodewords]
  var RS = {
    1: { L: [[1, 26, 19]], M: [[1, 26, 16]], Q: [[1, 26, 13]], H: [[1, 26, 9]] },
    2: { L: [[1, 44, 34]], M: [[1, 44, 28]], Q: [[1, 44, 22]], H: [[1, 44, 16]] },
    3: { L: [[1, 70, 55]], M: [[1, 70, 44]], Q: [[2, 35, 17]], H: [[2, 35, 13]] },
    4: { L: [[1, 100, 80]], M: [[2, 50, 32]], Q: [[2, 50, 24]], H: [[4, 25, 9]] },
    5: { L: [[1, 134, 108]], M: [[2, 67, 43]], Q: [[2, 33, 15], [2, 34, 16]], H: [[2, 33, 11], [2, 34, 12]] },
    6: { L: [[2, 86, 68]], M: [[4, 43, 27]], Q: [[4, 43, 19]], H: [[4, 43, 15]] }
  };

  // Galois field tables for Reed-Solomon over GF(256), prim 0x11d
  var EXP = new Array(512), LOG = new Array(256);
  (function () {
    var x = 1;
    for (var i = 0; i < 255; i++) { EXP[i] = x; LOG[x] = i; x <<= 1; if (x & 0x100) x ^= 0x11d; }
    for (var j = 255; j < 512; j++) EXP[j] = EXP[j - 255];
  })();
  function gfMul(a, b) { return (a === 0 || b === 0) ? 0 : EXP[LOG[a] + LOG[b]]; }

  function rsPoly(n) {
    var p = [1];
    for (var i = 0; i < n; i++) {
      var q = new Array(p.length + 1).fill(0);
      for (var j = 0; j < p.length; j++) {
        q[j] ^= p[j];
        q[j + 1] ^= gfMul(p[j], EXP[i]);
      }
      p = q;
    }
    return p;
  }

  function rsRemainder(data, ecCount) {
    var gen = rsPoly(ecCount);
    var buf = data.slice();
    for (var i = 0; i < ecCount; i++) buf.push(0);
    for (var k = 0; k < data.length; k++) {
      var coef = buf[k];
      if (!coef) continue;
      for (var m = 0; m < gen.length; m++) buf[k + m] ^= gfMul(gen[m], coef);
    }
    return buf.slice(data.length);
  }

  // BCH(15,5) for format info
  var G15 = (1 << 10) | (1 << 8) | (1 << 5) | (1 << 4) | (1 << 2) | (1 << 1) | (1 << 0);
  function bitLen(x) { var n = 0; while (x) { n++; x >>>= 1; } return n; }
  function formatBCH(data) {
    var d = data << 10;
    while (bitLen(d) - bitLen(G15) >= 0) d ^= G15 << (bitLen(d) - bitLen(G15));
    return ((data << 10) | d) ^ 0x5412;
  }

  function utf8(text) {
    var out = [], s = String(text || '');
    for (var i = 0; i < s.length; i++) {
      var c = s.charCodeAt(i);
      if (c < 0x80) out.push(c);
      else if (c < 0x800) out.push(0xc0 | (c >> 6), 0x80 | (c & 0x3f));
      else if (c >= 0xd800 && c <= 0xdbff && i + 1 < s.length) {
        var c2 = s.charCodeAt(++i);
        var cp = 0x10000 + (((c & 0x3ff) << 10) | (c2 & 0x3ff));
        out.push(0xf0 | (cp >> 18), 0x80 | ((cp >> 12) & 0x3f), 0x80 | ((cp >> 6) & 0x3f), 0x80 | (cp & 0x3f));
      } else out.push(0xe0 | (c >> 12), 0x80 | ((c >> 6) & 0x3f), 0x80 | (c & 0x3f));
    }
    return out;
  }

  function pickType(byteLen, ecKey) {
    for (var t = 1; t <= 6; t++) {
      var totalData = 0;
      RS[t][ecKey].forEach(function (g) { totalData += g[0] * g[2]; });
      // Header: 4-bit mode + 8-bit length (type<10)
      if (byteLen * 8 + 12 <= totalData * 8) return t;
    }
    throw new Error('QR data too large (max type 6); try shorter URL');
  }

  function BitBuf() { this.buf = []; this.length = 0; }
  BitBuf.prototype.put = function (n, bits) {
    for (var i = 0; i < bits; i++) {
      var bit = ((n >>> (bits - i - 1)) & 1) === 1;
      var idx = this.length >>> 3;
      if (this.buf.length <= idx) this.buf.push(0);
      if (bit) this.buf[idx] |= (0x80 >>> (this.length % 8));
      this.length++;
    }
  };

  function buildCodewords(bytes, type, ecKey) {
    var rs = RS[type][ecKey];
    var totalData = 0;
    rs.forEach(function (g) { totalData += g[0] * g[2]; });
    var bb = new BitBuf();
    bb.put(MODE_BYTE, 4);
    bb.put(bytes.length, 8);
    for (var i = 0; i < bytes.length; i++) bb.put(bytes[i], 8);
    if (bb.length + 4 <= totalData * 8) bb.put(0, 4);
    while (bb.length % 8 !== 0) bb.put(0, 1);
    var pad = [0xec, 0x11], p = 0;
    while (bb.buf.length < totalData) bb.buf.push(pad[p++ % 2]);

    var dBlocks = [], eBlocks = [], idx = 0;
    rs.forEach(function (g) {
      var n = g[0], total = g[1], dCw = g[2], eCw = total - dCw;
      for (var b = 0; b < n; b++) {
        var d = bb.buf.slice(idx, idx + dCw); idx += dCw;
        dBlocks.push(d); eBlocks.push(rsRemainder(d, eCw));
      }
    });

    var maxD = 0, maxE = 0;
    dBlocks.forEach(function (d) { if (d.length > maxD) maxD = d.length; });
    eBlocks.forEach(function (e) { if (e.length > maxE) maxE = e.length; });
    var out = [];
    for (var i = 0; i < maxD; i++) for (var j = 0; j < dBlocks.length; j++) if (i < dBlocks[j].length) out.push(dBlocks[j][i]);
    for (var i = 0; i < maxE; i++) for (var j = 0; j < eBlocks.length; j++) if (i < eBlocks[j].length) out.push(eBlocks[j][i]);
    return out;
  }

  function buildMatrix(type, ecKey, codewords) {
    var size = type * 4 + 17;
    var m = [], rsv = [];
    for (var r = 0; r < size; r++) { m.push(new Array(size).fill(false)); rsv.push(new Array(size).fill(false)); }

    function finder(rr, cc) {
      for (var i = -1; i <= 7; i++) for (var j = -1; j <= 7; j++) {
        var r = rr + i, c = cc + j;
        if (r < 0 || c < 0 || r >= size || c >= size) continue;
        var on = (i >= 0 && i <= 6 && (j === 0 || j === 6)) ||
                 (j >= 0 && j <= 6 && (i === 0 || i === 6)) ||
                 (i >= 2 && i <= 4 && j >= 2 && j <= 4);
        m[r][c] = on; rsv[r][c] = true;
      }
    }
    finder(0, 0); finder(0, size - 7); finder(size - 7, 0);

    // Timing
    for (var i = 8; i < size - 8; i++) {
      m[6][i] = (i % 2 === 0); rsv[6][i] = true;
      m[i][6] = (i % 2 === 0); rsv[i][6] = true;
    }
    // Dark module
    m[size - 8][8] = true; rsv[size - 8][8] = true;

    // Reserve format info area
    for (var i = 0; i < 9; i++) { if (!rsv[8][i]) rsv[8][i] = true; if (!rsv[i][8]) rsv[i][8] = true; }
    for (var i = 0; i < 8; i++) { rsv[size - 1 - i][8] = true; rsv[8][size - 1 - i] = true; }

    // Alignment (single center) for type 2..6
    if (type >= 2) {
      var ac = size - 7;
      for (var i = -2; i <= 2; i++) for (var j = -2; j <= 2; j++) {
        var r = ac + i, c = ac + j;
        if (rsv[r][c]) continue;
        var on = (Math.max(Math.abs(i), Math.abs(j)) !== 1);
        m[r][c] = on; rsv[r][c] = true;
      }
    }

    // Place data + mask 0 inline (mask: (i+j) % 2 === 0)
    var bitIdx = 0, total = codewords.length * 8;
    var col = size - 1, row = size - 1, dir = -1;
    while (col > 0) {
      if (col === 6) col--;
      while (true) {
        for (var dx = 0; dx < 2; dx++) {
          var c = col - dx;
          if (!rsv[row][c]) {
            var bit = false;
            if (bitIdx < total) {
              bit = ((codewords[bitIdx >> 3] >>> (7 - (bitIdx & 7))) & 1) === 1;
              bitIdx++;
            }
            if ((row + c) % 2 === 0) bit = !bit;
            m[row][c] = bit;
          }
        }
        row += dir;
        if (row < 0 || row >= size) { row -= dir; dir = -dir; col -= 2; break; }
      }
    }

    // Format info: ec(2) + mask(3 = 0)
    var fmt = (EC_BITS[ecKey] << 3) | 0;
    var bch = formatBCH(fmt);
    var getFmtBit = function (i) { return ((bch >> i) & 1) === 1; };

    // Top-left placement
    for (var i = 0; i <= 5; i++) m[i][8] = getFmtBit(i);
    m[7][8] = getFmtBit(6); m[8][8] = getFmtBit(7); m[8][7] = getFmtBit(8);
    for (var i = 9; i <= 14; i++) m[8][14 - i] = getFmtBit(i);

    // Bottom-left + top-right
    for (var i = 0; i <= 6; i++) m[size - 1 - i][8] = getFmtBit(i);
    for (var i = 7; i <= 14; i++) m[8][size - 15 + i] = getFmtBit(i);

    // Dark module again (in case overwritten)
    m[size - 8][8] = true;

    return { size: size, modules: m };
  }

  function encode(text, opts) {
    opts = opts || {};
    var ecKey = (opts.ecLevel || 'M').toUpperCase();
    if (!RS[1][ecKey]) ecKey = 'M';
    var bytes = utf8(text);
    var type = pickType(bytes.length, ecKey);
    var cw = buildCodewords(bytes, type, ecKey);
    return buildMatrix(type, ecKey, cw);
  }

  function renderSVG(matrix, opts) {
    opts = opts || {};
    var size = matrix.size;
    var quiet = opts.quietZone == null ? 4 : opts.quietZone;
    var ms = opts.moduleSize || 4;
    var fg = opts.fg || '#1C1917';
    var bg = opts.bg || '#FFFFFF';
    var dim = (size + quiet * 2) * ms;
    var rects = '';
    for (var r = 0; r < size; r++) for (var c = 0; c < size; c++) {
      if (matrix.modules[r][c]) {
        rects += '<rect x="' + ((c + quiet) * ms) + '" y="' + ((r + quiet) * ms) + '" width="' + ms + '" height="' + ms + '"/>';
      }
    }
    return '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ' + dim + ' ' + dim + '" shape-rendering="crispEdges">' +
      '<rect width="' + dim + '" height="' + dim + '" fill="' + bg + '"/>' +
      '<g fill="' + fg + '">' + rects + '</g></svg>';
  }

  root.KinQR = { encode: encode, renderSVG: renderSVG };
})(typeof window !== 'undefined' ? window : globalThis);
